import json,sys,importlib.util
def load(path):
    s=importlib.util.spec_from_file_location('c',path);m=importlib.util.module_from_spec(s);s.loader.exec_module(m);return m.p
d=json.load(open('data.json'))
allcases=d['train']+d['test']+d['arc-gen']
def test(p):
    return sum(p(e['input'])!=e['output'] for e in allcases)
if __name__=='__main__':
    p=load(sys.argv[1])
    print('fails',test(p),'of',len(allcases))

